13→
14→const SplashScreen = ({ onDone }) => {
15→  const videoRef = useRef(null);
16→  const [fadeOut, setFadeOut] = useState(false);
17→
18→  useEffect(() => {
19→    const video = videoRef.current;
20→    if (!video) return;
21→
22→    const handleEnd = () => {
23→      setFadeOut(true);
24→      setTimeout(() => onDone(), 500);
25→    };
26→
27→    video.addEventListener('ended', handleEnd);
28→
29→    const timer = setTimeout(() => {
30→      setFadeOut(true);
31→      setTimeout(() => onDone(), 500);
32→    }, 10000);
33→
34→    return () => {
35→      video.removeEventListener('ended', handleEnd);
36→      clearTimeout(timer);
37→    };
38→  }, [onDone]);
39→
40→  return (
41→    <div className={`splash-screen ${fadeOut ? 'splash-fade-out' : ''}`}>
42→      <video
43→        ref={videoRef}
44→        src="/splash.mp4"
45→        autoPlay
46→        muted
47→        playsInline
48→        className="splash-video"
49→      />
50→    </div>
51→  );
52→};
53→
54→function App() {
55→  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
56→  const [activeTab, setActiveTab] = useState('run');
57→  const [showSplash, setShowSplash] = useState(true);
58→
59→  const handleLogin = (userData) => {
60→    localStorage.setItem('user', JSON.stringify(userData));
61→    setUser(userData);
62→  };
63→
64→  const handleLogout = () => {
65→    localStorage.removeItem('user');
66→    localStorage.removeItem('token');
67→    setUser(null);
68→    setActiveTab('run');
69→  };
70→
71→  const renderContent = () => {
72→    switch (activeTab) {
73→      case 'run': return <Dashboard user={user} />;
74→      case 'report': return <ReportsPanel user={user} />;
75→      case 'mechanic': return <MechanicPanel user={user} />;
76→      case 'admin': return <AdminPanel user={user} />;
77→      case 'master': return <MasterPanel user={user} />;
78→      case 'nazoratchi': return <NazoratchiPanel user={user} />;
79→      case 'users': return <UsersPanel user={user} />;
80→      case 'asnova': return <AsnovaPanel user={user} />;
81→      default: return <Dashboard user={user} />;
82→    }
83→  };
84→
85→  if (showSplash) {
86→    return <SplashScreen onDone={() => setShowSplash(false)} />;
87→  }
88→
89→  return (
90→    <Router>
91→      <Routes>
92→        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
93→        <Route path="/*" element={
94→          user ? (
95→            <div className="app-container app-appear">
96→              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
97→              <div className="main-content">
98→                {renderContent()}
99→              </div>
100→            </div>
101→          ) : (
102→            <Navigate to="/login" />
103→          )
104→        } />
105→      </Routes>
106→    </Router>
107→  );
108→}
109→
110→export default App;
EOF

